module otsu_threshold (  
    input wire [7:0] pixel_value,  
    input wire [7:0] threshold,  
    input wire enable,  
    output reg obf_binary_output  
);  
    always @(*) begin  
        if (enable) begin  
            if (pixel_value >= threshold)  
                obf_binary_output = 1;  
            else  
                obf_binary_output = 0;  
        end else begin  
            obf_binary_output = 0;  
        end  
    end  
endmodule
